from html.parser import HTMLParser
from pathlib import Path
import unittest

from tests.frontend_harness import run_dashboard


ROOT = Path(__file__).resolve().parents[2]


class WatchButtonParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.attributes = None

    def handle_starttag(self, tag, attrs):
        if tag == "button" and dict(attrs).get("id") == "watchIncident":
            self.attributes = dict(attrs)


class WatchIncidentAccessibilityTest(unittest.TestCase):
    def test_watch_button_has_accessible_name_and_preserves_behavior(self):
        parser = WatchButtonParser()
        parser.feed((ROOT / "index.html").read_text())

        self.assertIsNotNone(parser.attributes)
        self.assertEqual("Watch incident", parser.attributes["aria-label"])

        state = run_dashboard(["#watchIncident"])
        self.assertEqual("true", state["watching"])
        self.assertEqual("Watching incident", state["watchStatus"])


if __name__ == "__main__":
    unittest.main()
